import json, urllib.request, os, sys

def post_comment(body):
    token = os.environ.get("GITHUB_TOKEN", "")
    repo = os.environ.get("GITHUB_REPOSITORY", "")
    pr_number = os.environ.get("PR_NUMBER", "")
    if not token or not repo or not pr_number:
        print("Missing env vars for posting comment")
        return
    data = json.dumps({"body": body}).encode()
    url = f"https://api.github.com/repos/{repo}/issues/{pr_number}/comments"
    req = urllib.request.Request(url, data=data, headers={
        "Authorization": f"token {token}",
        "Accept": "application/vnd.github.v3+json",
        "Content-Type": "application/json"
    })
    try:
        with urllib.request.urlopen(req) as resp:
            print(f"Posted comment: {resp.status}")
    except Exception as e:
        print(f"Failed to post comment: {e}")

# 1. Gemini Review
print("Running Gemini review...")
with open("/tmp/pr.diff") as f:
    diff = f.read()

gemini_prompt = "You are an expert code reviewer. Review this PR diff. Format: SUMMARY / ISSUES (with severity) / VERDICT.\n\nDiff:\n" + diff
gemini_data = json.dumps({
    "contents": [{"parts": [{"text": gemini_prompt}]}]
}).encode()

gemini_key = os.environ.get("GEMINI_API_KEY", "")
gemini_req = urllib.request.Request(
    f"https://generativelanguage.googleapis.com/v1beta/models/gemini-3.5-flash:generateContent?key={gemini_key}",
    data=gemini_data,
    headers={"Content-Type": "application/json"}
)
gemini_text = ""
try:
    with urllib.request.urlopen(gemini_req) as resp:
        result = json.loads(resp.read())
        if result.get("candidates"):
            gemini_text = result["candidates"][0]["content"]["parts"][0]["text"]
except Exception as e:
    gemini_text = f"Gemini error: {e}"
print(f"Gemini done: {gemini_text[:100]}")

post_comment(f"## Gemini Code Review\n\n```\n{gemini_text}\n```\n\n*Generated by Gemini AI*")

# 2. StepFun Review
print("Running StepFun review...")
stepfun_prompt = f"You are an expert code reviewer. Gemini already reviewed this PR below. Provide your own analysis.\n\nGemini review:\n{gemini_text}\n\nDiff:\n{diff}"

stepfun_data = json.dumps({
    "model": "step-3.7-flash",
    "messages": [{"role": "user", "content": stepfun_prompt}]
}).encode()

stepfun_key = os.environ.get("STEPFUN_API_KEY", "")
stepfun_req = urllib.request.Request(
    "https://api.stepfun.com/step_plan/v1/chat/completions",
    data=stepfun_data,
    headers={
        "Content-Type": "application/json",
        "Authorization": f"Bearer {stepfun_key}"
    }
)
stepfun_text = ""
try:
    with urllib.request.urlopen(stepfun_req) as resp:
        result = json.loads(resp.read())
        stepfun_text = result["choices"][0]["message"]["content"]
except Exception as e:
    stepfun_text = f"StepFun error: {e}"
print(f"StepFun done: {stepfun_text[:100]}")

post_comment(f"## Claude Review (StepFun)\n\n```\n{stepfun_text}\n```\n\n*Generated by Claude via StepFun*")

# 3. Summary
post_comment("## AI Collaborative Review — Summary\n\nAll AIs have reviewed this PR. See individual comments above.\n\n*Gemini + Claude (StepFun) collaborative review*")

print("All done!")
